import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as o}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as t,o as l,c as n,a2 as i}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Safety/cloudflare-api-token.md","filePath":"cs-CZ/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),r={name:"cs-CZ/Safety/cloudflare-api-token.md"};function d(s,e,p,u,c,h){return l(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Přihlašovací údaje Cloudflare API umožňují ImgBed vyčistit CDN cache Cloudflare po změnách souborů.</p><p><img src="'+a+'" alt="Nastavení Cloudflare API Tokenu" loading="lazy"></p><h2 id="kde-nastavit" tabindex="-1">Kde nastavit <a class="header-anchor" href="#kde-nastavit" aria-label="Permalink to &quot;Kde nastavit&quot;">​</a></h2><p>Otevřete administraci a přejděte na:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Je potřeba vyplnit:</p><ul><li>Zone ID</li><li>E-mail účtu</li><li>API Key</li></ul><h2 id="co-toto-nastaveni-dela" tabindex="-1">Co toto nastavení dělá <a class="header-anchor" href="#co-toto-nastaveni-dela" aria-label="Permalink to &quot;Co toto nastavení dělá&quot;">​</a></h2><p>Cloudflare může cacheovat veřejné URL obrázků.</p><p>Cache zrychluje doručování obrázků, ale může také způsobit, že starý obsah bude ještě chvíli viditelný po smazání, zablokování, nahrazení nebo přesunutí souboru.</p><p>Po nastavení Cloudflare API údajů se ImgBed po těchto operacích pokusí vyčistit související cache Cloudflare.</p><p>Hodí se to, když:</p><ul><li>smažete obrázek a chcete, aby veřejný odkaz co nejrychleji přestal fungovat.</li><li>zablokujete obrázek a chcete, aby návštěvníci neviděli původní soubor.</li><li>nahradíte soubor se stejným názvem a chcete, aby návštěvníci dříve viděli novou verzi.</li><li>přesunete nebo přejmenujete soubory a chcete rychle obnovit cache starých cest.</li><li>změníte pravidla veřejného přístupu a chcete dříve aktualizovat veřejnou galerii nebo cache náhodných obrázků.</li></ul><h2 id="co-kdyz-pole-nechate-prazdna" tabindex="-1">Co když pole necháte prázdná <a class="header-anchor" href="#co-kdyz-pole-nechate-prazdna" aria-label="Permalink to &quot;Co když pole necháte prázdná&quot;">​</a></h2><p>ImgBed funguje normálně i bez tohoto nastavení.</p><p>Jediný rozdíl je, že ImgBed nebude aktivně čistit CDN cache Cloudflare. Návštěvníci mohou vidět starý obsah, dokud cache Cloudflare přirozeně nevyprší.</p><h2 id="jak-najit-zone-id" tabindex="-1">Jak najít Zone ID <a class="header-anchor" href="#jak-najit-zone-id" aria-label="Permalink to &quot;Jak najít Zone ID&quot;">​</a></h2><p>Zone ID je Cloudflare Zone ID webu, který používá vaše doména ImgBed.</p><ol><li>Přihlaste se do Cloudflare Dashboard.</li><li>Otevřete web, který obsahuje vaši doménu ImgBed.</li><li>Na přehledové stránce webu najděte <code>Zone ID</code>.</li><li>Zkopírujte ho do pole <code>Zone ID</code> v ImgBed.</li></ol><p>Jde o Zone ID webu, ne account ID.</p><h2 id="e-mail-uctu" tabindex="-1">E-mail účtu <a class="header-anchor" href="#e-mail-uctu" aria-label="Permalink to &quot;E-mail účtu&quot;">​</a></h2><p>Zadejte e-mailovou adresu, kterou používáte pro přihlášení do Cloudflare.</p><p>Musí odpovídat API Key zadanému níže.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Zadejte Cloudflare Global API Key.</p><ol><li>Přihlaste se do Cloudflare Dashboard.</li><li>Otevřete svůj profil.</li><li>Přejděte na stránku API Tokens.</li><li>Najděte <code>Global API Key</code>.</li><li>Zobrazte a zkopírujte ho.</li><li>Vložte ho do pole <code>API Key</code> v ImgBed.</li></ol><p><img src="'+o+'" alt="Zobrazení global API key" loading="lazy"></p><h2 id="kdy-se-projevi" tabindex="-1">Kdy se projeví <a class="header-anchor" href="#kdy-se-projevi" aria-label="Permalink to &quot;Kdy se projeví&quot;">​</a></h2><p>Po vyplnění polí uložte nastavení.</p><p>Budoucí změny souborů se automaticky pokusí vyčistit cache Cloudflare. Dřívější operace se zpětně nečistí. Pokud jste soubor smazali nebo nahradili před tímto nastavením, počkejte na vypršení cache Cloudflare nebo ji vyčistěte ručně v Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="je-to-povinne" tabindex="-1">Je to povinné? <a class="header-anchor" href="#je-to-povinne" aria-label="Permalink to &quot;Je to povinné?&quot;">​</a></h3><p>Ne.</p><p>Pokud vaše doména nepoužívá Cloudflare nebo vám nevadí zpoždění CDN cache, můžete pole nechat prázdná.</p><h3 id="rozbije-spatne-nastaveni-upload" tabindex="-1">Rozbije špatné nastavení upload? <a class="header-anchor" href="#rozbije-spatne-nastaveni-upload" aria-label="Permalink to &quot;Rozbije špatné nastavení upload?&quot;">​</a></h3><p>Obvykle ne.</p><p>Špatné údaje jen zabrání čištění cache Cloudflare. Upload a běžný přístup k souborům by měly fungovat dál.</p><h3 id="proc-lze-smazany-obrazek-stale-otevrit" tabindex="-1">Proč lze smazaný obrázek stále otevřít? <a class="header-anchor" href="#proc-lze-smazany-obrazek-stale-otevrit" aria-label="Permalink to &quot;Proč lze smazaný obrázek stále otevřít?&quot;">​</a></h3><p>Nejčastější důvod je, že Cloudflare má starý soubor stále v cache.</p><p>Se správnými Cloudflare API údaji ImgBed při smazání souboru vyčistí cache příslušného URL.</p><h3 id="proc-po-nahrazeni-souboru-stale-vidim-stary-obrazek" tabindex="-1">Proč po nahrazení souboru stále vidím starý obrázek? <a class="header-anchor" href="#proc-po-nahrazeni-souboru-stale-vidim-stary-obrazek" aria-label="Permalink to &quot;Proč po nahrazení souboru stále vidím starý obrázek?&quot;">​</a></h3><p>I to obvykle způsobuje CDN cache.</p><p>Po nastavení této funkce se ImgBed pokusí vyčistit cache starého URL při přepsání souboru se stejným názvem.</p>',44)])])}const z=t(r,[["render",d]]);export{k as __pageData,z as default};
